import { render, screen, fireEvent, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React, { useState } from 'react';
import { useDebounce } from './useDebounce';

function Harness({ delay = 300 }: { delay?: number }) {
  const [text, setText] = useState('');
  const debounced = useDebounce(text, delay);
  return (
    <div>
      <input data-testid="input" value={text} onChange={e => setText(e.target.value)} />
      <span data-testid="debounced">{debounced}</span>
    </div>
  );
}

describe('useDebounce', () => {
  beforeEach(() => {
    jest.useFakeTimers();
  });
  afterEach(() => {
    jest.useRealTimers();
  });

  it('returns the initial value immediately', () => {
    render(<Harness />);
    expect(screen.getByTestId('debounced')).toHaveTextContent('');
  });

  it('does not update the debounced value before delay', () => {
    render(<Harness delay={500} />);
    fireEvent.change(screen.getByTestId('input'), { target: { value: 'hello' } });
    act(() => { jest.advanceTimersByTime(300); });
    expect(screen.getByTestId('debounced')).toHaveTextContent('');
  });

  it('updates the debounced value after delay', () => {
    render(<Harness delay={500} />);
    fireEvent.change(screen.getByTestId('input'), { target: { value: 'hello' } });
    act(() => { jest.advanceTimersByTime(500); });
    expect(screen.getByTestId('debounced')).toHaveTextContent('hello');
  });

  it('resets the timer when value changes', () => {
    render(<Harness delay={500} />);
    fireEvent.change(screen.getByTestId('input'), { target: { value: 'he' } });
    act(() => { jest.advanceTimersByTime(400); });
    fireEvent.change(screen.getByTestId('input'), { target: { value: 'hello' } });
    act(() => { jest.advanceTimersByTime(400); });
    expect(screen.getByTestId('debounced')).toHaveTextContent('');
    act(() => { jest.advanceTimersByTime(100); });
    expect(screen.getByTestId('debounced')).toHaveTextContent('hello');
  });

  it('uses default delay of 300ms', () => {
    render(<Harness />);
    fireEvent.change(screen.getByTestId('input'), { target: { value: 'test' } });
    act(() => { jest.advanceTimersByTime(299); });
    expect(screen.getByTestId('debounced')).toHaveTextContent('');
    act(() => { jest.advanceTimersByTime(1); });
    expect(screen.getByTestId('debounced')).toHaveTextContent('test');
  });
});

